var COURSE_PL_SQ = [{day: 1, title: `Pierwsze powitania i grzeczność`, title_native: `Përshëndetjet e para`, focus: `Zaczynasz podróż w Tiranie i uczysz się najprostszych zwrotów, które przydadzą się w hotelu, kawiarni i sklepie. Celem jest umieć przywitać się, podziękować i pożegnać bez stresu.`, vocab: [{sq: `mirë`, pl: `dobrze`, ipa: `/mir/`},{sq: `dita`, pl: `dzień`, ipa: `/di-ta/`},{sq: `natë`, pl: `noc`, ipa: `/nat/`},{sq: `faleminderit`, pl: `dziękuję`, ipa: `/fa-le-min-de-rit/`},{sq: `po`, pl: `tak`, ipa: `/po/`},{sq: `jo`, pl: `nie`, ipa: `/jo/`},{sq: `ju`, pl: `pan, pani, wy`, ipa: `/ju/`},{sq: `unë`, pl: `ja`, ipa: `/u-nə/`},{sq: `emër`, pl: `imię`, ipa: `/e-mər/`},{sq: `shqip`, pl: `po albańsku`, ipa: `/szczip/`}], phrases: [{sq: `Mirëdita.`, pl: `Dzień dobry.`, ipa: `/mir-di-ta/`},{sq: `Mirëmëngjes.`, pl: `Dzień dobry rano.`, ipa: `/mir-mən-gjes/`},{sq: `Mirëmbrëma.`, pl: `Dobry wieczór.`, ipa: `/mir-mbrə-ma/`},{sq: `Faleminderit.`, pl: `Dziękuję.`, ipa: `/fa-le-min-de-rit/`},{sq: `Mirupafshim.`, pl: `Do widzenia.`, ipa: `/mi-ru-paf-szim/`},{sq: `Po, ju lutem.`, pl: `Tak, proszę.`, ipa: `/po ju lu-tem/`}], grammar: `W albańskim często używa się formy grzecznościowej ju, podobnie jak polskie „pan/pani”. Zwrot ju lutem oznacza „proszę”, ale dosłownie ma sens uprzejmej prośby. Na początku podróży najbezpieczniej używać pełnych, grzecznych form.`, practice: [`Przywitaj recepcjonistę rano po albańsku.`,`Powiedz „dziękuję” po otrzymaniu kawy.`,`Połącz Mirëdita, Faleminderit i Mirupafshim w krótką scenkę.`,`Przećwicz odpowiedź „tak, proszę” i „nie, dziękuję”.`,`Wypowiedz swoje imię, zaczynając od Unë jam...`]},{day: 2, title: `Przedstawianie się`, title_native: `Prezantimi`, focus: `Jesteś w hostelu w Prisztinie i poznajesz innych podróżnych. Nauczysz się mówić, jak się nazywasz, skąd jesteś i że jesteś z Polski.`, vocab: [{sq: `jam`, pl: `jestem`, ipa: `/jam/`},{sq: `quhem`, pl: `nazywam się`, ipa: `/czu-hem/`},{sq: `nga`, pl: `z, od`, ipa: `/nga/`},{sq: `Polonia`, pl: `Polska`, ipa: `/po-lo-ni-a/`},{sq: `Shqipëria`, pl: `Albania`, ipa: `/szczi-pə-ri-a/`},{sq: `Kosova`, pl: `Kosowo`, ipa: `/ko-so-va/`},{sq: `student`, pl: `student`, ipa: `/stu-dent/`},{sq: `turist`, pl: `turysta`, ipa: `/tu-rist/`},{sq: `mik`, pl: `przyjaciel`, ipa: `/mik/`},{sq: `kënaqësi`, pl: `przyjemność`, ipa: `/kə-na-czə-si/`}], phrases: [{sq: `Unë jam nga Polonia.`, pl: `Jestem z Polski.`, ipa: `/u-nə jam nga po-lo-ni-a/`},{sq: `Si quheni?`, pl: `Jak się pan/pani nazywa?`, ipa: `/si czu-he-ni/`},{sq: `Unë quhem Anna.`, pl: `Nazywam się Anna.`, ipa: `/u-nə czu-hem an-na/`},{sq: `Gëzohem që ju njoh.`, pl: `Miło pana/panią poznać.`, ipa: `/gə-zo-hem czə ju njoh/`},{sq: `A jeni turist?`, pl: `Czy jest pan/pani turystą?`, ipa: `/a je-ni tu-rist/`},{sq: `Po, jam turist.`, pl: `Tak, jestem turystą.`, ipa: `/po jam tu-rist/`}], grammar: `Czasownik jam oznacza „jestem” i jest bardzo przydatny od pierwszego dnia. Albańskie zdania często nie wymagają osobnego zaimka, ale na początku możesz mówić Unë jam, żeby brzmieć jasno. Pytania można tworzyć przez intonację lub partykułę a na początku.`, practice: [`Powiedz: „Jestem z Polski” po albańsku.`,`Zapytaj kogoś uprzejmie o imię.`,`Przedstaw się jako turysta.`,`Utwórz krótką rozmowę: imię, kraj, miłe poznanie.`,`Zamień imię Anna na własne imię.`]},{day: 3, title: `Liczby od 0 do 20`, title_native: `Numrat nga zero në njëzet`, focus: `W sklepie w Szkodrze potrzebujesz rozumieć ceny, numery pokoi i godziny. Dziś poznajesz podstawowe liczby używane w podróży.`, vocab: [{sq: `zero`, pl: `zero`, ipa: `/ze-ro/`},{sq: `një`, pl: `jeden`, ipa: `/ńə/`},{sq: `dy`, pl: `dwa`, ipa: `/dy/`},{sq: `tre`, pl: `trzy`, ipa: `/tre/`},{sq: `katër`, pl: `cztery`, ipa: `/ka-tər/`},{sq: `pesë`, pl: `pięć`, ipa: `/pe-sə/`},{sq: `gjashtë`, pl: `sześć`, ipa: `/gjaszt/`},{sq: `shtatë`, pl: `siedem`, ipa: `/szta-tə/`},{sq: `tetë`, pl: `osiem`, ipa: `/te-tə/`},{sq: `dhjetë`, pl: `dziesięć`, ipa: `/djet/`}], phrases: [{sq: `Një kafe, ju lutem.`, pl: `Jedną kawę, proszę.`, ipa: `/ńə ka-fe ju lu-tem/`},{sq: `Dy bileta, ju lutem.`, pl: `Dwa bilety, proszę.`, ipa: `/dy bi-le-ta ju lu-tem/`},{sq: `Sa kushton?`, pl: `Ile to kosztuje?`, ipa: `/sa kush-ton/`},{sq: `Është dhjetë euro.`, pl: `To jest dziesięć euro.`, ipa: `/əszt djet eu-ro/`},{sq: `Kam tre ditë këtu.`, pl: `Mam tu trzy dni.`, ipa: `/kam tre di-tə kə-tu/`},{sq: `Numri im është pesë.`, pl: `Mój numer to pięć.`, ipa: `/num-ri im əszt pe-sə/`}], grammar: `Liczebniki w albańskim stoją zwykle przed rzeczownikiem: një kafe, dy bileta. Po liczbie rzeczownik może przyjmować formę liczby mnogiej, ale w praktyce turystycznej najważniejsze jest, by liczba była zrozumiała. Sa kushton? to jedno z najważniejszych pytań zakupowych.`, practice: [`Policz od 0 do 10 na głos.`,`Zamów jedną kawę i dwa bilety.`,`Zapytaj o cenę pamiątki.`,`Powiedz, że masz trzy dni w mieście.`,`Zapisz po albańsku liczby: 1, 2, 3, 5, 10.`]},{day: 4, title: `Podstawowe pytania`, title_native: `Pyetjet bazë`, focus: `Spacerujesz po centrum Tirany i potrzebujesz zadawać proste pytania. Dziś ćwiczysz słowa: kto, co, gdzie, kiedy i ile.`, vocab: [{sq: `kush`, pl: `kto`, ipa: `/kusz/`},{sq: `çfarë`, pl: `co`, ipa: `/czfa-rə/`},{sq: `ku`, pl: `gdzie`, ipa: `/ku/`},{sq: `kur`, pl: `kiedy`, ipa: `/kur/`},{sq: `sa`, pl: `ile`, ipa: `/sa/`},{sq: `pse`, pl: `dlaczego`, ipa: `/pse/`},{sq: `si`, pl: `jak`, ipa: `/si/`},{sq: `këtu`, pl: `tutaj`, ipa: `/kə-tu/`},{sq: `atje`, pl: `tam`, ipa: `/a-tje/`},{sq: `tani`, pl: `teraz`, ipa: `/ta-ni/`}], phrases: [{sq: `Ku është hoteli?`, pl: `Gdzie jest hotel?`, ipa: `/ku əszt ho-te-li/`},{sq: `Çfarë është kjo?`, pl: `Co to jest?`, ipa: `/czfa-rə əszt kjo/`},{sq: `Sa kushton kjo?`, pl: `Ile to kosztuje?`, ipa: `/sa kush-ton kjo/`},{sq: `Kur hapet muzeu?`, pl: `Kiedy otwiera się muzeum?`, ipa: `/kur ha-pet mu-ze-u/`},{sq: `Si jeni?`, pl: `Jak się pan/pani ma?`, ipa: `/si je-ni/`},{sq: `Kush është ai?`, pl: `Kto to jest?`, ipa: `/kusz əszt aj/`}], grammar: `W albańskim słowa pytające zwykle stoją na początku zdania. Është oznacza „jest”, a kjo oznacza „to” dla rodzaju żeńskiego lub rzeczy bliskiej. W mowie codziennej pytanie często rozpoznasz po intonacji nawet bez zmiany szyku.`, practice: [`Zapytaj, gdzie jest hotel.`,`Zapytaj, co to jest, wskazując przedmiot.`,`Zapytaj o godzinę otwarcia muzeum.`,`Ułóż trzy pytania z ku, sa i kur.`,`Odpowiedz krótko: këtu albo atje.`]},{day: 5, title: `W hotelu i meldowanie`, title_native: `Në hotel`, focus: `Przyjeżdżasz do hotelu w Durrës i musisz się zameldować. Nauczysz się słów związanych z pokojem, rezerwacją i dokumentami.`, vocab: [{sq: `hotel`, pl: `hotel`, ipa: `/ho-tel/`},{sq: `dhomë`, pl: `pokój`, ipa: `/dho-mə/`},{sq: `rezervim`, pl: `rezerwacja`, ipa: `/re-zer-vim/`},{sq: `pasaportë`, pl: `paszport`, ipa: `/pa-sa-por-tə/`},{sq: `çelës`, pl: `klucz`, ipa: `/cze-ləs/`},{sq: `kat`, pl: `piętro`, ipa: `/kat/`},{sq: `ashensor`, pl: `winda`, ipa: `/a-shen-sor/`},{sq: `mëngjes`, pl: `śniadanie`, ipa: `/mən-gjes/`},{sq: `natë`, pl: `noc`, ipa: `/nat/`},{sq: `adresë`, pl: `adres`, ipa: `/a-dre-sə/`}], phrases: [{sq: `Kam një rezervim.`, pl: `Mam rezerwację.`, ipa: `/kam ńə re-zer-vim/`},{sq: `Dua të bëj check-in.`, pl: `Chcę się zameldować.`, ipa: `/du-a tə bəj czek-in/`},{sq: `Ja pasaporta ime.`, pl: `Oto mój paszport.`, ipa: `/ja pa-sa-por-ta i-me/`},{sq: `Ku është dhoma ime?`, pl: `Gdzie jest mój pokój?`, ipa: `/ku əszt dho-ma i-me/`},{sq: `A ka mëngjes?`, pl: `Czy jest śniadanie?`, ipa: `/a ka mən-gjes/`},{sq: `Në cilin kat është?`, pl: `Na którym to piętrze?`, ipa: `/nə ci-lin kat əszt/`}], grammar: `Kam znaczy „mam”, a dua znaczy „chcę”. Konstrukcja dua të bëj oznacza „chcę zrobić”, bardzo przydatna w hotelu i na lotnisku. Słowo ime oznacza „moja/mój” i stoi zwykle po rzeczowniku: dhoma ime.`, practice: [`Powiedz recepcji, że masz rezerwację.`,`Poproś o informację, gdzie jest pokój.`,`Zapytaj, czy hotel ma śniadanie.`,`Przećwicz zdanie z paszportem.`,`Ułóż dialog: recepcjonista prosi o paszport, ty odpowiadasz.`]},{day: 6, title: `Orientacja w mieście`, title_native: `Orientimi në qytet`, focus: `Jesteś w Berat i szukasz starego miasta, mostu i przystanku. Dziś uczysz się pytać o drogę i rozumieć proste wskazówki.`, vocab: [{sq: `qytet`, pl: `miasto`, ipa: `/czy-tet/`},{sq: `rrugë`, pl: `ulica, droga`, ipa: `/rru-gə/`},{sq: `shesh`, pl: `plac`, ipa: `/szesz/`},{sq: `urë`, pl: `most`, ipa: `/u-rə/`},{sq: `majtas`, pl: `w lewo`, ipa: `/maj-tas/`},{sq: `djathtas`, pl: `w prawo`, ipa: `/dja-thtas/`},{sq: `drejt`, pl: `prosto`, ipa: `/drejt/`},{sq: `afër`, pl: `blisko`, ipa: `/a-fər/`},{sq: `larg`, pl: `daleko`, ipa: `/larg/`},{sq: `këndi`, pl: `róg`, ipa: `/kən-di/`}], phrases: [{sq: `Ku është qendra?`, pl: `Gdzie jest centrum?`, ipa: `/ku əszt czen-dra/`},{sq: `Shkoni drejt.`, pl: `Proszę iść prosto.`, ipa: `/szko-ni drejt/`},{sq: `Kthehuni majtas.`, pl: `Proszę skręcić w lewo.`, ipa: `/kthe-hu-ni maj-tas/`},{sq: `Kthehuni djathtas.`, pl: `Proszę skręcić w prawo.`, ipa: `/kthe-hu-ni dja-thtas/`},{sq: `A është larg?`, pl: `Czy to daleko?`, ipa: `/a əszt larg/`},{sq: `Është afër.`, pl: `To jest blisko.`, ipa: `/əszt a-fər/`}], grammar: `Tryb uprzejmy w wskazówkach często kończy się na -ni, jak shkoni, kthehuni. To forma grzeczna i bezpieczna w rozmowie z nieznajomymi. Kierunki majtas i djathtas są kluczowe, bo pojawią się w taksówce, na ulicy i przy mapie.`, practice: [`Zapytaj o centrum miasta.`,`Powiedz komuś: idź prosto, potem w lewo.`,`Zapytaj, czy zamek jest daleko.`,`Odpowiedz: to jest blisko.`,`Narysuj prostą mapkę i opisz trasę trzema zdaniami.`]},{day: 7, title: `Kawiarnia i napoje`, title_native: `Në kafene`, focus: `Siadasz w kawiarni w Tiranie przy Blloku i zamawiasz kawę, wodę lub herbatę. Dziś ćwiczysz naturalne zwroty kelnerskie.`, vocab: [{sq: `kafe`, pl: `kawa`, ipa: `/ka-fe/`},{sq: `çaj`, pl: `herbata`, ipa: `/czaj/`},{sq: `ujë`, pl: `woda`, ipa: `/u-jə/`},{sq: `qumësht`, pl: `mleko`, ipa: `/czu-məszt/`},{sq: `sheqer`, pl: `cukier`, ipa: `/sze-czer/`},{sq: `gotë`, pl: `szklanka`, ipa: `/go-tə/`},{sq: `filxhan`, pl: `filiżanka`, ipa: `/fil-dżan/`},{sq: `ftohtë`, pl: `zimny`, ipa: `/ftoht/`},{sq: `nxehtë`, pl: `gorący`, ipa: `/ndzeht/`},{sq: `tavolinë`, pl: `stolik`, ipa: `/ta-vo-li-nə/`}], phrases: [{sq: `Një kafe, ju lutem.`, pl: `Jedną kawę, proszę.`, ipa: `/ńə ka-fe ju lu-tem/`},{sq: `Pa sheqer, ju lutem.`, pl: `Bez cukru, proszę.`, ipa: `/pa sze-czer ju lu-tem/`},{sq: `Me qumësht.`, pl: `Z mlekiem.`, ipa: `/me czu-məszt/`},{sq: `Dua ujë të ftohtë.`, pl: `Chcę zimną wodę.`, ipa: `/du-a u-jə tə ftoht/`},{sq: `A ka tavolinë të lirë?`, pl: `Czy jest wolny stolik?`, ipa: `/a ka ta-vo-li-nə tə li-rə/`},{sq: `Faturën, ju lutem.`, pl: `Rachunek, proszę.`, ipa: `/fa-tu-rən ju lu-tem/`}], grammar: `Me oznacza „z”, a pa oznacza „bez”. To bardzo prosta para przy zamawianiu: me qumësht, pa sheqer. W albańskim rodzajnik określony często przykleja się na końcu rzeczownika, dlatego faturë to „rachunek”, a faturën to „ten rachunek”.`, practice: [`Zamów kawę bez cukru.`,`Poproś o wodę zimną.`,`Zapytaj o wolny stolik.`,`Powiedz „z mlekiem” i „bez mleka”.`,`Ułóż krótką scenkę z kelnerem i rachunkiem.`]},{day: 8, title: `Jedzenie i śniadanie`, title_native: `Ushqimi dhe mëngjesi`, focus: `Rano w Gjirokastrze szukasz prostego śniadania. Nauczysz się nazw podstawowych potraw i sposobów proszenia o menu.`, vocab: [{sq: `ushqim`, pl: `jedzenie`, ipa: `/usz-czim/`},{sq: `bukë`, pl: `chleb`, ipa: `/bu-kə/`},{sq: `djathë`, pl: `ser`, ipa: `/djath/`},{sq: `vezë`, pl: `jajko`, ipa: `/ve-zə/`},{sq: `gjalpë`, pl: `masło`, ipa: `/gjal-pə/`},{sq: `mish`, pl: `mięso`, ipa: `/misz/`},{sq: `peshk`, pl: `ryba`, ipa: `/peszk/`},{sq: `perime`, pl: `warzywa`, ipa: `/pe-ri-me/`},{sq: `fruta`, pl: `owoce`, ipa: `/fru-ta/`},{sq: `menu`, pl: `menu`, ipa: `/me-nu/`}], phrases: [{sq: `A keni menu?`, pl: `Czy macie menu?`, ipa: `/a ke-ni me-nu/`},{sq: `Çfarë rekomandoni?`, pl: `Co pan/pani poleca?`, ipa: `/czfa-rə re-ko-man-do-ni/`},{sq: `Dua mëngjes.`, pl: `Chcę śniadanie.`, ipa: `/du-a mən-gjes/`},{sq: `A ka vezë?`, pl: `Czy są jajka?`, ipa: `/a ka ve-zə/`},{sq: `Nuk ha mish.`, pl: `Nie jem mięsa.`, ipa: `/nuk ha misz/`},{sq: `Është shumë mirë.`, pl: `To jest bardzo dobre.`, ipa: `/əszt szu-mə mir/`}], grammar: `Nuk stawia się przed czasownikiem, żeby zrobić przeczenie: nuk ha oznacza „nie jem”. To bardzo ważne przy diecie, alergiach i preferencjach. Shumë znaczy „bardzo” lub „dużo”, zależnie od kontekstu.`, practice: [`Poproś o menu.`,`Powiedz, że nie jesz mięsa.`,`Zapytaj, co kelner poleca.`,`Zamów śniadanie z jajkiem i chlebem.`,`Skomentuj, że jedzenie jest bardzo dobre.`]},{day: 9, title: `Restauracja i zamawianie obiadu`, title_native: `Në restorant`, focus: `Jesz obiad nad morzem w Vlorë i chcesz zamówić spokojnie, bez pośpiechu. Dziś ćwiczysz zamówienia, prośby i pytania o składniki.`, vocab: [{sq: `restorant`, pl: `restauracja`, ipa: `/res-to-rant/`},{sq: `pjatë`, pl: `talerz, danie`, ipa: `/pja-tə/`},{sq: `supë`, pl: `zupa`, ipa: `/su-pə/`},{sq: `sallatë`, pl: `sałatka`, ipa: `/sal-la-tə/`},{sq: `oriz`, pl: `ryż`, ipa: `/o-riz/`},{sq: `patate`, pl: `ziemniaki`, ipa: `/pa-ta-te/`},{sq: `kripë`, pl: `sól`, ipa: `/kri-pə/`},{sq: `piper`, pl: `pieprz`, ipa: `/pi-per/`},{sq: `vaj`, pl: `olej`, ipa: `/vaj/`},{sq: `verë`, pl: `wino`, ipa: `/ve-rə/`}], phrases: [{sq: `Dua këtë pjatë.`, pl: `Chcę to danie.`, ipa: `/du-a kə-tə pja-tə/`},{sq: `A është pikante?`, pl: `Czy to jest ostre?`, ipa: `/a əszt pi-kan-te/`},{sq: `Pa kripë, ju lutem.`, pl: `Bez soli, proszę.`, ipa: `/pa kri-pə ju lu-tem/`},{sq: `Mund të porosis?`, pl: `Czy mogę zamówić?`, ipa: `/mund tə po-ro-sis/`},{sq: `Edhe një ujë, ju lutem.`, pl: `Jeszcze jedną wodę, proszę.`, ipa: `/e-dhe ńə u-jə ju lu-tem/`},{sq: `Ishte shumë e shijshme.`, pl: `Było bardzo smaczne.`, ipa: `/isz-te szu-mə e szij-szme/`}], grammar: `Këtë oznacza „to/tę” przy wskazywaniu konkretnej rzeczy. W restauracji możesz używać prostych zdań z dua këtë, nawet jeśli nie znasz nazwy dania. Mund të... oznacza „czy mogę...” i brzmi uprzejmie.`, practice: [`Zamów konkretne danie z menu.`,`Zapytaj, czy potrawa jest ostra.`,`Poproś o danie bez soli.`,`Powiedz, że jedzenie było smaczne.`,`Ułóż dialog, w którym prosisz o jeszcze jedną wodę.`]},{day: 10, title: `Zakupy i ceny`, title_native: `Blerjet dhe çmimet`, focus: `Na targu w Krujë oglądasz pamiątki i owoce. Nauczysz się pytać o ceny, rozmiary i możliwość płatności kartą.`, vocab: [{sq: `dyqan`, pl: `sklep`, ipa: `/dy-czan/`},{sq: `treg`, pl: `targ`, ipa: `/treg/`},{sq: `çmim`, pl: `cena`, ipa: `/czmim/`},{sq: `para`, pl: `pieniądze`, ipa: `/pa-ra/`},{sq: `kartë`, pl: `karta`, ipa: `/kar-tə/`},{sq: `lek`, pl: `lek, waluta albańska`, ipa: `/lek/`},{sq: `çantë`, pl: `torba`, ipa: `/czan-tə/`},{sq: `dhuratë`, pl: `prezent`, ipa: `/dhu-ra-tə/`},{sq: `i lirë`, pl: `tani`, ipa: `/i li-rə/`},{sq: `i shtrenjtë`, pl: `drogi`, ipa: `/i sztrenjt/`}], phrases: [{sq: `Sa kushton kjo?`, pl: `Ile to kosztuje?`, ipa: `/sa kush-ton kjo/`},{sq: `A mund të paguaj me kartë?`, pl: `Czy mogę zapłacić kartą?`, ipa: `/a mund tə pa-gu-aj me kar-tə/`},{sq: `Është shumë shtrenjtë.`, pl: `To jest bardzo drogie.`, ipa: `/əszt szu-mə sztrenjt/`},{sq: `A keni diçka më të lirë?`, pl: `Czy macie coś tańszego?`, ipa: `/a ke-ni di-czka mə tə li-rə/`},{sq: `Dua ta blej.`, pl: `Chcę to kupić.`, ipa: `/du-a ta blej/`},{sq: `Më jepni një çantë.`, pl: `Proszę dać mi torbę.`, ipa: `/mə jep-ni ńə czan-tə/`}], grammar: `Më oznacza „mi/mnie”, a më jepni znaczy „proszę mi dać”. Przymiotniki często występują po rzeczowniku, ale w stałych zwrotach turystycznych najważniejsze są gotowe formy: i lirë i i shtrenjtë. Przy płatności kartą użyjesz me kartë.`, practice: [`Zapytaj o cenę pamiątki.`,`Powiedz, że coś jest za drogie.`,`Poproś o coś tańszego.`,`Zapytaj, czy możesz zapłacić kartą.`,`Kup prezent i poproś o torbę.`]},{day: 11, title: `Transport publiczny`, title_native: `Transporti publik`, focus: `W Tiranie chcesz pojechać autobusem do innej części miasta. Nauczysz się kupować bilety, pytać o przystanek i kierunek.`, vocab: [{sq: `autobus`, pl: `autobus`, ipa: `/au-to-bus/`},{sq: `biletë`, pl: `bilet`, ipa: `/bi-le-tə/`},{sq: `stacion`, pl: `stacja, przystanek`, ipa: `/sta-cion/`},{sq: `linjë`, pl: `linia`, ipa: `/liń-ə/`},{sq: `qendër`, pl: `centrum`, ipa: `/czen-dər/`},{sq: `aeroport`, pl: `lotnisko`, ipa: `/a-e-ro-port/`},{sq: `tren`, pl: `pociąg`, ipa: `/tren/`},{sq: `orë`, pl: `godzina`, ipa: `/o-rə/`},{sq: `nisje`, pl: `odjazd`, ipa: `/nis-je/`},{sq: `mbërritje`, pl: `przyjazd`, ipa: `/mbə-rrit-je/`}], phrases: [{sq: `Ku është stacioni?`, pl: `Gdzie jest przystanek?`, ipa: `/ku əszt sta-cio-ni/`},{sq: `Dua një biletë.`, pl: `Chcę jeden bilet.`, ipa: `/du-a ńə bi-le-tə/`},{sq: `A shkon në qendër?`, pl: `Czy jedzie do centrum?`, ipa: `/a szkon nə czen-dər/`},{sq: `Në cilën orë niset?`, pl: `O której godzinie odjeżdża?`, ipa: `/nə ci-lən o-rə ni-set/`},{sq: `Sa zgjat udhëtimi?`, pl: `Ile trwa podróż?`, ipa: `/sa zgja-t udhə-ti-mi/`},{sq: `Zbres këtu.`, pl: `Wysiadam tutaj.`, ipa: `/zbres kə-tu/`}], grammar: `Në oznacza „w”, „do” lub „na” zależnie od kontekstu: në qendër to „do centrum” albo „w centrum”. Czasownik shkon oznacza „idzie/jedzie”, więc działa dla ludzi i transportu. Zbres znaczy „wysiadam” i warto je znać w autobusie lub taksówce.`, practice: [`Zapytaj, gdzie jest przystanek.`,`Kup jeden bilet do centrum.`,`Zapytaj, czy autobus jedzie na lotnisko.`,`Zapytaj, ile trwa podróż.`,`Powiedz kierowcy, że wysiadasz tutaj.`]},{day: 12, title: `Taksówka i aplikacje przejazdowe`, title_native: `Taksi dhe udhëtimet`, focus: `Po kolacji w Tiranie bierzesz taksówkę do hotelu. Dziś ćwiczysz adresy, cenę przejazdu i prośby do kierowcy.`, vocab: [{sq: `taksi`, pl: `taksówka`, ipa: `/tak-si/`},{sq: `shofer`, pl: `kierowca`, ipa: `/szo-fer/`},{sq: `adresë`, pl: `adres`, ipa: `/a-dre-sə/`},{sq: `hotel`, pl: `hotel`, ipa: `/ho-tel/`},{sq: `majtas`, pl: `w lewo`, ipa: `/maj-tas/`},{sq: `djathtas`, pl: `w prawo`, ipa: `/dja-thtas/`},{sq: `ndaloni`, pl: `proszę się zatrzymać`, ipa: `/nda-lo-ni/`},{sq: `shpejt`, pl: `szybko`, ipa: `/szpejt/`},{sq: `ngadalë`, pl: `wolno`, ipa: `/nga-da-lə/`},{sq: `këtu`, pl: `tutaj`, ipa: `/kə-tu/`}], phrases: [{sq: `Dua një taksi.`, pl: `Chcę taksówkę.`, ipa: `/du-a ńə tak-si/`},{sq: `Më çoni në këtë adresë.`, pl: `Proszę mnie zawieźć pod ten adres.`, ipa: `/mə czo-ni nə kə-tə a-dre-sə/`},{sq: `Sa kushton deri atje?`, pl: `Ile kosztuje do tamtego miejsca?`, ipa: `/sa kush-ton de-ri a-tje/`},{sq: `Ju lutem, më ngadalë.`, pl: `Proszę wolniej.`, ipa: `/ju lu-tem mə nga-da-lə/`},{sq: `Ndaloni këtu, ju lutem.`, pl: `Proszę zatrzymać się tutaj.`, ipa: `/nda-lo-ni kə-tu ju lu-tem/`},{sq: `Kthehuni djathtas këtu.`, pl: `Proszę skręcić tutaj w prawo.`, ipa: `/kthe-hu-ni dja-thtas kə-tu/`}], grammar: `Më çoni oznacza „proszę mnie zawieźć” i jest bardzo praktyczne w taksówce. Dery atje oznacza „do tamtego miejsca”. Formy z -ni, takie jak ndaloni i kthehuni, brzmią uprzejmie i jasno.`, practice: [`Poproś kierowcę o kurs pod adres.`,`Zapytaj o cenę przed rozpoczęciem jazdy.`,`Powiedz „proszę wolniej”.`,`Poproś o zatrzymanie tutaj.`,`Opisz kierowcy trasę: prosto, w prawo, potem w lewo.`]},{day: 13, title: `Czas, dni i plan dnia`, title_native: `Koha dhe ditët`, focus: `Planujesz zwiedzanie w Korçë i chcesz ustalić godziny otwarcia. Nauczysz się mówić o czasie, dniach tygodnia i prostych planach.`, vocab: [{sq: `sot`, pl: `dziś`, ipa: `/sot/`},{sq: `nesër`, pl: `jutro`, ipa: `/ne-sər/`},{sq: `dje`, pl: `wczoraj`, ipa: `/dje/`},{sq: `ditë`, pl: `dzień`, ipa: `/di-tə/`},{sq: `javë`, pl: `tydzień`, ipa: `/ja-və/`},{sq: `orë`, pl: `godzina`, ipa: `/o-rə/`},{sq: `mëngjes`, pl: `rano`, ipa: `/mən-gjes/`},{sq: `drekë`, pl: `południe, obiad`, ipa: `/dre-kə/`},{sq: `mbrëmje`, pl: `wieczór`, ipa: `/mbrəm-je/`},{sq: `natë`, pl: `noc`, ipa: `/nat/`}], phrases: [{sq: `Sa është ora?`, pl: `Która jest godzina?`, ipa: `/sa əszt o-ra/`},{sq: `Është ora tetë.`, pl: `Jest ósma.`, ipa: `/əszt o-ra te-tə/`},{sq: `Kur hapet?`, pl: `Kiedy się otwiera?`, ipa: `/kur ha-pet/`},{sq: `Kur mbyllet?`, pl: `Kiedy się zamyka?`, ipa: `/kur mbyl-let/`},{sq: `Do të vij nesër.`, pl: `Przyjdę jutro.`, ipa: `/do tə vij ne-sər/`},{sq: `Sot jam i zënë.`, pl: `Dziś jestem zajęty.`, ipa: `/sot jam i zə-nə/`}], grammar: `Do të + czasownik tworzy prostą przyszłość, np. do të vij oznacza „przyjdę”. To łatwy sposób na mówienie o planach podróży. Kur oznacza „kiedy” i przydaje się przy godzinach otwarcia, rezerwacjach i spotkaniach.`, practice: [`Zapytaj o godzinę.`,`Powiedz, że przyjdziesz jutro.`,`Zapytaj, kiedy muzeum się otwiera.`,`Zapytaj, kiedy sklep się zamyka.`,`Ułóż plan dnia: rano kawa, potem muzeum, wieczorem kolacja.`]},{day: 14, title: `Rodzina i ludzie`, title_native: `Familja dhe njerëzit`, focus: `Rozmawiasz z lokalną osobą w kawiarni w Prizrenie. Nauczysz się prostych słów o rodzinie i relacjach, przydatnych w small talku.`, vocab: [{sq: `familje`, pl: `rodzina`, ipa: `/fa-mil-je/`},{sq: `nënë`, pl: `mama`, ipa: `/nə-nə/`},{sq: `baba`, pl: `tata`, ipa: `/ba-ba/`},{sq: `motër`, pl: `siostra`, ipa: `/mo-tər/`},{sq: `vëlla`, pl: `brat`, ipa: `/vəl-la/`},{sq: `fëmijë`, pl: `dziecko`, ipa: `/fə-mi-jə/`},{sq: `grua`, pl: `kobieta, żona`, ipa: `/gru-a/`},{sq: `burrë`, pl: `mężczyzna, mąż`, ipa: `/bur-rə/`},{sq: `shok`, pl: `kolega`, ipa: `/szok/`},{sq: `shoqe`, pl: `koleżanka`, ipa: `/szo-cze/`}], phrases: [{sq: `Kam një motër.`, pl: `Mam jedną siostrę.`, ipa: `/kam ńə mo-tər/`},{sq: `Kam dy vëllezër.`, pl: `Mam dwóch braci.`, ipa: `/kam dy vəl-le-zər/`},{sq: `Familja ime është në Poloni.`, pl: `Moja rodzina jest w Polsce.`, ipa: `/fa-mil-ja i-me əszt nə po-lo-ni/`},{sq: `A keni fëmijë?`, pl: `Czy ma pan/pani dzieci?`, ipa: `/a ke-ni fə-mi-jə/`},{sq: `Jam këtu me shokun tim.`, pl: `Jestem tu z moim kolegą.`, ipa: `/jam kə-tu me szo-kun tim/`},{sq: `Kjo është shoqja ime.`, pl: `To jest moja koleżanka.`, ipa: `/kjo əszt szo-cja i-me/`}], grammar: `Zaimek dzierżawczy często stoi po rzeczowniku: familja ime, shoku im. Forma może się zmieniać zależnie od rodzaju i określoności rzeczownika, ale w praktyce ucz się całych fraz. Me oznacza „z” i działa zarówno dla osób, jak i dodatków do jedzenia.`, practice: [`Powiedz, że twoja rodzina jest w Polsce.`,`Przedstaw kolegę lub koleżankę.`,`Powiedz, ilu masz braci lub sióstr.`,`Zapytaj uprzejmie, czy ktoś ma dzieci.`,`Napisz trzy zdania o swojej rodzinie po albańsku.`]},{day: 15, title: `Pogoda i ubrania`, title_native: `Moti dhe rrobat`, focus: `Wybierasz się nad Jezioro Ochrydzkie i sprawdzasz pogodę. Nauczysz się mówić o słońcu, deszczu, temperaturze i ubraniach.`, vocab: [{sq: `mot`, pl: `pogoda`, ipa: `/mot/`},{sq: `diell`, pl: `słońce`, ipa: `/di-el/`},{sq: `shi`, pl: `deszcz`, ipa: `/szi/`},{sq: `erë`, pl: `wiatr`, ipa: `/e-rə/`},{sq: `ftohtë`, pl: `zimno`, ipa: `/ftoht/`},{sq: `nxehtë`, pl: `gorąco`, ipa: `/ndzeht/`},{sq: `xhaketë`, pl: `kurtka`, ipa: `/dża-ke-tə/`},{sq: `këpucë`, pl: `buty`, ipa: `/kə-pu-cə/`},{sq: `bluzë`, pl: `bluzka, koszulka`, ipa: `/blu-zə/`},{sq: `pantallona`, pl: `spodnie`, ipa: `/pan-tal-lo-na/`}], phrases: [{sq: `Si është moti?`, pl: `Jaka jest pogoda?`, ipa: `/si əszt mo-ti/`},{sq: `Sot ka diell.`, pl: `Dziś jest słońce.`, ipa: `/sot ka di-el/`},{sq: `Po bie shi.`, pl: `Pada deszcz.`, ipa: `/po bie szi/`},{sq: `Është shumë ftohtë.`, pl: `Jest bardzo zimno.`, ipa: `/əszt szu-mə ftoht/`},{sq: `Kam nevojë për një xhaketë.`, pl: `Potrzebuję kurtki.`, ipa: `/kam ne-vo-jə pər ńə dża-ke-tə/`},{sq: `A keni këpucë të rehatshme?`, pl: `Czy macie wygodne buty?`, ipa: `/a ke-ni kə-pu-cə tə re-hat-szme/`}], grammar: `Po przed czasownikiem może oznaczać czynność trwającą: po bie shi to „pada deszcz”. Kam nevojë për oznacza „potrzebuję” i jest bardzo praktyczne w sklepie oraz aptece. Przymiotnik zwykle stoi po rzeczowniku: këpucë të rehatshme.`, practice: [`Zapytaj o pogodę.`,`Powiedz, że dziś jest słońce.`,`Powiedz, że pada deszcz.`,`Poproś w sklepie o wygodne buty.`,`Powiedz, że potrzebujesz kurtki.`]},{day: 16, title: `Plaża i natura`, title_native: `Plazhi dhe natyra`, focus: `Spędzasz dzień na plaży w Ksamilu i pytasz o ręcznik, wodę oraz miejsce do pływania. Dziś słownictwo dotyczy morza, plaży i wypoczynku.`, vocab: [{sq: `plazh`, pl: `plaża`, ipa: `/plazh/`},{sq: `det`, pl: `morze`, ipa: `/det/`},{sq: `liqen`, pl: `jezioro`, ipa: `/li-czen/`},{sq: `mal`, pl: `góra`, ipa: `/mal/`},{sq: `rërë`, pl: `piasek`, ipa: `/rə-rə/`},{sq: `diell`, pl: `słońce`, ipa: `/di-el/`},{sq: `ujë`, pl: `woda`, ipa: `/u-jə/`},{sq: `peshqir`, pl: `ręcznik`, ipa: `/pesz-czir/`},{sq: `ombrellë`, pl: `parasol`, ipa: `/om-brel-lə/`},{sq: `not`, pl: `pływanie`, ipa: `/not/`}], phrases: [{sq: `Ku është plazhi?`, pl: `Gdzie jest plaża?`, ipa: `/ku əszt pla-zhi/`},{sq: `A mund të notoj këtu?`, pl: `Czy mogę tu pływać?`, ipa: `/a mund tə no-toj kə-tu/`},{sq: `Dua një ombrellë.`, pl: `Chcę parasol.`, ipa: `/du-a ńə om-brel-lə/`},{sq: `Kam nevojë për peshqir.`, pl: `Potrzebuję ręcznika.`, ipa: `/kam ne-vo-jə pər pesz-czir/`},{sq: `Uji është i pastër.`, pl: `Woda jest czysta.`, ipa: `/u-ji əszt i pas-tər/`},{sq: `Është shumë bukur këtu.`, pl: `Tutaj jest bardzo pięknie.`, ipa: `/əszt szu-mə bu-kur kə-tu/`}], grammar: `A mund të...? oznacza „czy mogę...?” i jest przydatne, gdy pytasz o zgodę. Bukur oznacza „pięknie” lub „ładnie” i często usłyszysz je w komentarzach o miejscach. W albańskim rodzajnik określony może zmieniać formę rzeczownika: ujë to woda, uji to ta woda.`, practice: [`Zapytaj, gdzie jest plaża.`,`Zapytaj, czy możesz tu pływać.`,`Poproś o parasol.`,`Powiedz, że woda jest czysta.`,`Opisz miejsce jednym zachwyconym zdaniem.`]},{day: 17, title: `Zdrowie i apteka`, title_native: `Shëndeti dhe farmacia`, focus: `Potrzebujesz pomocy w aptece w Tiranie. Nauczysz się mówić, że coś cię boli, poprosić o lekarstwo i opisać podstawowe objawy.`, vocab: [{sq: `farmaci`, pl: `apteka`, ipa: `/far-ma-ci/`},{sq: `ilaç`, pl: `lekarstwo`, ipa: `/i-lacz/`},{sq: `mjek`, pl: `lekarz`, ipa: `/mjek/`},{sq: `dhimbje`, pl: `ból`, ipa: `/dhim-bje/`},{sq: `kokë`, pl: `głowa`, ipa: `/ko-kə/`},{sq: `bark`, pl: `brzuch`, ipa: `/bark/`},{sq: `fyt`, pl: `gardło`, ipa: `/fyt/`},{sq: `temperaturë`, pl: `temperatura`, ipa: `/tem-pe-ra-tu-rə/`},{sq: `alergji`, pl: `alergia`, ipa: `/a-ler-gji/`},{sq: `ujë`, pl: `woda`, ipa: `/u-jə/`}], phrases: [{sq: `Ku është farmacia?`, pl: `Gdzie jest apteka?`, ipa: `/ku əszt far-ma-ci-a/`},{sq: `Kam dhimbje koke.`, pl: `Boli mnie głowa.`, ipa: `/kam dhim-bje ko-ke/`},{sq: `Kam dhimbje barku.`, pl: `Boli mnie brzuch.`, ipa: `/kam dhim-bje bar-ku/`},{sq: `Kam alergji.`, pl: `Mam alergię.`, ipa: `/kam a-ler-gji/`},{sq: `A keni ilaç për dhimbje?`, pl: `Czy macie lekarstwo na ból?`, ipa: `/a ke-ni i-lacz pər dhim-bje/`},{sq: `Kam nevojë për mjek.`, pl: `Potrzebuję lekarza.`, ipa: `/kam ne-vo-jə pər mjek/`}], grammar: `Kam dhimbje... dosłownie znaczy „mam ból...” i jest naturalnym sposobem opisywania dolegliwości. Për oznacza „dla/na”, więc ilaç për dhimbje to lekarstwo na ból. W sytuacjach zdrowotnych mów krótko i jasno.`, practice: [`Zapytaj o najbliższą aptekę.`,`Powiedz, że boli cię głowa.`,`Powiedz, że masz alergię.`,`Poproś o lekarstwo na ból.`,`Powiedz, że potrzebujesz lekarza.`]},{day: 18, title: `Problemy i pomoc`, title_native: `Problemet dhe ndihma`, focus: `W podróży czasem trzeba zgłosić problem: zgubiony bagaż, brak internetu albo pomyłkę w rachunku. Dziś uczysz się prosić o pomoc spokojnie i konkretnie.`, vocab: [{sq: `problem`, pl: `problem`, ipa: `/pro-blem/`},{sq: `ndihmë`, pl: `pomoc`, ipa: `/ndih-mə/`},{sq: `polici`, pl: `policja`, ipa: `/po-li-ci/`},{sq: `çantë`, pl: `torba`, ipa: `/czan-tə/`},{sq: `telefon`, pl: `telefon`, ipa: `/te-le-fon/`},{sq: `internet`, pl: `internet`, ipa: `/in-ter-net/`},{sq: `gabim`, pl: `błąd`, ipa: `/ga-bim/`},{sq: `humbur`, pl: `zgubiony`, ipa: `/hum-bur/`},{sq: `rrezik`, pl: `niebezpieczeństwo`, ipa: `/rre-zik/`},{sq: `siguri`, pl: `bezpieczeństwo`, ipa: `/si-gu-ri/`}], phrases: [{sq: `Kam një problem.`, pl: `Mam problem.`, ipa: `/kam ńə pro-blem/`},{sq: `Ju lutem, më ndihmoni.`, pl: `Proszę, pomóżcie mi.`, ipa: `/ju lu-tem mə ndih-mo-ni/`},{sq: `Kam humbur çantën.`, pl: `Zgubiłem torbę.`, ipa: `/kam hum-bur czan-tən/`},{sq: `Telefoni im nuk punon.`, pl: `Mój telefon nie działa.`, ipa: `/te-le-fo-ni im nuk pu-non/`},{sq: `Nuk ka internet.`, pl: `Nie ma internetu.`, ipa: `/nuk ka in-ter-net/`},{sq: `Ku është policia?`, pl: `Gdzie jest policja?`, ipa: `/ku əszt po-li-ci-a/`}], grammar: `Më ndihmoni to uprzejma prośba „proszę mi pomóc”. Nuk punon oznacza „nie działa” i możesz używać tego przy telefonie, karcie, klimatyzacji lub Wi-Fi. Kam humbur oznacza „zgubiłem/zgubiłam”.`, practice: [`Powiedz, że masz problem.`,`Poproś o pomoc.`,`Powiedz, że zgubiłeś torbę.`,`Powiedz, że telefon nie działa.`,`Zapytaj, gdzie jest policja.`]},{day: 19, title: `Lotnisko i bagaż`, title_native: `Aeroporti dhe bagazhi`, focus: `Przylatujesz na lotnisko w Tiranie i musisz odebrać bagaż oraz znaleźć transport. Dziś ćwiczysz słowa związane z odprawą, lotem i walizką.`, vocab: [{sq: `aeroport`, pl: `lotnisko`, ipa: `/a-e-ro-port/`},{sq: `fluturim`, pl: `lot`, ipa: `/flu-tu-rim/`},{sq: `bagazh`, pl: `bagaż`, ipa: `/ba-gazh/`},{sq: `valixhe`, pl: `walizka`, ipa: `/va-li-dże/`},{sq: `pasaportë`, pl: `paszport`, ipa: `/pa-sa-por-tə/`},{sq: `kontroll`, pl: `kontrola`, ipa: `/kon-troll/`},{sq: `dalje`, pl: `wyjście`, ipa: `/dal-je/`},{sq: `hyrje`, pl: `wejście`, ipa: `/hyr-je/`},{sq: `vonë`, pl: `późno`, ipa: `/vo-nə/`},{sq: `në kohë`, pl: `na czas`, ipa: `/nə ko-hə/`}], phrases: [{sq: `Ku është bagazhi?`, pl: `Gdzie jest bagaż?`, ipa: `/ku əszt ba-ga-zhi/`},{sq: `Kam humbur valixhen.`, pl: `Zgubiłem walizkę.`, ipa: `/kam hum-bur va-li-dżen/`},{sq: `Fluturimi është vonë.`, pl: `Lot jest opóźniony.`, ipa: `/flu-tu-ri-mi əszt vo-nə/`},{sq: `Ku është dalja?`, pl: `Gdzie jest wyjście?`, ipa: `/ku əszt dal-ja/`},{sq: `Kam vetëm një çantë.`, pl: `Mam tylko jedną torbę.`, ipa: `/kam ve-təm ńə czan-tə/`},{sq: `A është ky fluturimi im?`, pl: `Czy to jest mój lot?`, ipa: `/a əszt ky flu-tu-ri-mi im/`}], grammar: `Vetëm oznacza „tylko” i przydaje się przy bagażu oraz zamówieniach. Ky oznacza „ten” dla rodzaju męskiego, a kjo „ta/to” dla wielu rzeczy bliskich. Na lotnisku warto mówić krótkimi zdaniami: pasaportë, bagazh, dalje.`, practice: [`Zapytaj, gdzie jest bagaż.`,`Powiedz, że zgubiłeś walizkę.`,`Zapytaj, gdzie jest wyjście.`,`Powiedz, że masz tylko jedną torbę.`,`Zapytaj, czy to jest twój lot.`]},{day: 20, title: `Rezerwacje i telefon`, title_native: `Rezervimet dhe telefoni`, focus: `Chcesz zarezerwować stolik telefonicznie w Sarandzie. Nauczysz się podawać godzinę, liczbę osób i prosić o potwierdzenie.`, vocab: [{sq: `telefonatë`, pl: `rozmowa telefoniczna`, ipa: `/te-le-fo-na-tə/`},{sq: `rezervim`, pl: `rezerwacja`, ipa: `/re-zer-vim/`},{sq: `tavolinë`, pl: `stolik`, ipa: `/ta-vo-li-nə/`},{sq: `person`, pl: `osoba`, ipa: `/per-son/`},{sq: `emër`, pl: `imię`, ipa: `/e-mər/`},{sq: `numër`, pl: `numer`, ipa: `/nu-mər/`},{sq: `sot`, pl: `dziś`, ipa: `/sot/`},{sq: `nesër`, pl: `jutro`, ipa: `/ne-sər/`},{sq: `konfirmim`, pl: `potwierdzenie`, ipa: `/kon-fir-mim/`},{sq: `mesazh`, pl: `wiadomość`, ipa: `/me-sazh/`}], phrases: [{sq: `Dua të bëj një rezervim.`, pl: `Chcę zrobić rezerwację.`, ipa: `/du-a tə bəj ńə re-zer-vim/`},{sq: `Për dy persona.`, pl: `Dla dwóch osób.`, ipa: `/pər dy per-so-na/`},{sq: `Në orën shtatë.`, pl: `O siódmej.`, ipa: `/nə o-rən szta-tə/`},{sq: `Emri im është...`, pl: `Moje imię to...`, ipa: `/em-ri im əszt/`},{sq: `Numri im është...`, pl: `Mój numer to...`, ipa: `/num-ri im əszt/`},{sq: `A mund të më dërgoni konfirmim?`, pl: `Czy mogą państwo wysłać mi potwierdzenie?`, ipa: `/a mund tə mə dər-go-ni kon-fir-mim/`}], grammar: `Për dy persona oznacza „dla dwóch osób”, a liczbę można łatwo zmieniać. Në orën... służy do podawania godziny spotkania lub rezerwacji. Dërgoni znaczy „wysyłacie/proszę wysłać” w formie grzecznej.`, practice: [`Zarezerwuj stolik dla dwóch osób.`,`Podaj godzinę siódmą.`,`Podaj swoje imię.`,`Poproś o potwierdzenie wiadomością.`,`Odegraj krótką rozmowę telefoniczną z restauracją.`]},{day: 21, title: `Ubrania i rozmiary`, title_native: `Rrobat dhe masat`, focus: `Kupujesz koszulkę lub kurtkę w centrum handlowym w Tiranie. Dziś poznajesz rozmiary, kolory i pytania o przymierzalnię.`, vocab: [{sq: `rroba`, pl: `ubrania`, ipa: `/rro-ba/`},{sq: `masë`, pl: `rozmiar`, ipa: `/ma-sə/`},{sq: `ngjyrë`, pl: `kolor`, ipa: `/ndży-rə/`},{sq: `e bardhë`, pl: `biała`, ipa: `/e bar-dhə/`},{sq: `e zezë`, pl: `czarna`, ipa: `/e ze-zə/`},{sq: `e kuqe`, pl: `czerwona`, ipa: `/e ku-cze/`},{sq: `e kaltër`, pl: `niebieska`, ipa: `/e kal-tər/`},{sq: `këmishë`, pl: `koszula`, ipa: `/kə-miszə/`},{sq: `fustan`, pl: `sukienka`, ipa: `/fus-tan/`},{sq: `provë`, pl: `przymiarka`, ipa: `/pro-və/`}], phrases: [{sq: `A keni këtë në masë më të madhe?`, pl: `Czy macie to w większym rozmiarze?`, ipa: `/a ke-ni kə-tə nə ma-sə mə tə ma-dhe/`},{sq: `A keni ngjyrë tjetër?`, pl: `Czy macie inny kolor?`, ipa: `/a ke-ni ndży-rə tje-tər/`},{sq: `Dua ta provoj.`, pl: `Chcę to przymierzyć.`, ipa: `/du-a ta pro-voj/`},{sq: `Ku është kabina?`, pl: `Gdzie jest przymierzalnia?`, ipa: `/ku əszt ka-bi-na/`},{sq: `Është shumë e vogël.`, pl: `To jest za małe.`, ipa: `/əszt szu-mə e vo-gəl/`},{sq: `Është shumë e madhe.`, pl: `To jest za duże.`, ipa: `/əszt szu-mə e ma-dhe/`}], grammar: `Më të madhe oznacza „większy/większą”, a më të vogël „mniejszy/mniejszą”. Stopień wyższy często tworzy się za pomocą më. Przy ubraniach możesz mówić prosto: shumë e vogël albo shumë e madhe.`, practice: [`Zapytaj o większy rozmiar.`,`Zapytaj o inny kolor.`,`Powiedz, że chcesz coś przymierzyć.`,`Zapytaj o przymierzalnię.`,`Powiedz, że ubranie jest za małe albo za duże.`]},{day: 22, title: `Zwiedzanie i kultura`, title_native: `Turizmi dhe kultura`, focus: `Zwiedzasz zamek w Gjirokastrze i muzeum w Tiranie. Nauczysz się pytać o bilety, zdjęcia, godziny i przewodnika.`, vocab: [{sq: `muze`, pl: `muzeum`, ipa: `/mu-ze/`},{sq: `kështjellë`, pl: `zamek`, ipa: `/kəszt-jel-lə/`},{sq: `biletë`, pl: `bilet`, ipa: `/bi-le-tə/`},{sq: `udhërrëfyes`, pl: `przewodnik`, ipa: `/udhə-rrə-fjes/`},{sq: `foto`, pl: `zdjęcie`, ipa: `/fo-to/`},{sq: `histori`, pl: `historia`, ipa: `/his-to-ri/`},{sq: `hyrje`, pl: `wejście`, ipa: `/hyr-je/`},{sq: `dalje`, pl: `wyjście`, ipa: `/dal-je/`},{sq: `hapur`, pl: `otwarte`, ipa: `/ha-pur/`},{sq: `mbyllur`, pl: `zamknięte`, ipa: `/mbyl-lur/`}], phrases: [{sq: `Dua dy bileta.`, pl: `Chcę dwa bilety.`, ipa: `/du-a dy bi-le-ta/`},{sq: `A lejohet fotografia?`, pl: `Czy wolno robić zdjęcia?`, ipa: `/a le-jo-het fo-to-gra-fi-a/`},{sq: `A ka udhërrëfyes?`, pl: `Czy jest przewodnik?`, ipa: `/a ka udhə-rrə-fjes/`},{sq: `Muzeu është i hapur?`, pl: `Czy muzeum jest otwarte?`, ipa: `/mu-ze-u əszt i ha-pur/`},{sq: `Në cilën orë mbyllet?`, pl: `O której godzinie się zamyka?`, ipa: `/nə ci-lən o-rə mbyl-let/`},{sq: `Ku është hyrja?`, pl: `Gdzie jest wejście?`, ipa: `/ku əszt hyr-ja/`}], grammar: `I hapur i i mbyllur oznaczają „otwarty” i „zamknięty” dla rodzaju męskiego; forma żeńska często zaczyna się od e. Lejohet oznacza „jest dozwolone”, bardzo przydatne przy zdjęciach i zasadach. A na początku zdania pomaga tworzyć pytania tak/nie.`, practice: [`Kup dwa bilety do muzeum.`,`Zapytaj, czy wolno robić zdjęcia.`,`Zapytaj o przewodnika.`,`Zapytaj, o której muzeum się zamyka.`,`Znajdź wejście i wyjście, używając albańskich słów.`]},{day: 23, title: `Mieszkanie i codzienne potrzeby`, title_native: `Shtëpia dhe nevojat e përditshme`, focus: `Wynajmujesz apartament na kilka dni w Tiranie i potrzebujesz zapytać o Wi-Fi, pralkę i kuchnię. Dziś ćwiczysz praktyczne słowa z mieszkania.`, vocab: [{sq: `shtëpi`, pl: `dom`, ipa: `/sz-tə-pi/`},{sq: `apartament`, pl: `apartament`, ipa: `/a-par-ta-ment/`},{sq: `dhomë`, pl: `pokój`, ipa: `/dho-mə/`},{sq: `kuzhinë`, pl: `kuchnia`, ipa: `/ku-zhi-nə/`},{sq: `banjë`, pl: `łazienka`, ipa: `/bań-ə/`},{sq: `krevat`, pl: `łóżko`, ipa: `/kre-vat/`},{sq: `çelës`, pl: `klucz`, ipa: `/cze-ləs/`},{sq: `lavatrice`, pl: `pralka`, ipa: `/la-va-tri-cze/`},{sq: `internet`, pl: `internet`, ipa: `/in-ter-net/`},{sq: `dritare`, pl: `okno`, ipa: `/dri-ta-re/`}], phrases: [{sq: `Ku është çelësi?`, pl: `Gdzie jest klucz?`, ipa: `/ku əszt cze-lə-si/`},{sq: `A ka internet?`, pl: `Czy jest internet?`, ipa: `/a ka in-ter-net/`},{sq: `A mund të përdor kuzhinën?`, pl: `Czy mogę używać kuchni?`, ipa: `/a mund tə pər-dor ku-zhi-nən/`},{sq: `Lavatricja nuk punon.`, pl: `Pralka nie działa.`, ipa: `/la-va-tri-cja nuk pu-non/`},{sq: `Kam nevojë për peshqir.`, pl: `Potrzebuję ręcznika.`, ipa: `/kam ne-vo-jə pər pesz-czir/`},{sq: `Dritarja nuk hapet.`, pl: `Okno się nie otwiera.`, ipa: `/dri-tar-ja nuk ha-pet/`}], grammar: `Përdor oznacza „używam”, a mund të përdor to „czy mogę używać”. Przy zgłaszaniu usterek używaj nuk punon albo nuk hapet. To proste konstrukcje, które załatwią większość problemów w apartamencie.`, practice: [`Zapytaj, gdzie jest klucz.`,`Zapytaj, czy jest internet.`,`Poproś o możliwość używania kuchni.`,`Zgłoś, że pralka nie działa.`,`Powiedz, że potrzebujesz ręcznika.`]},{day: 24, title: `Rozmowy towarzyskie`, title_native: `Biseda shoqërore`, focus: `Spotykasz lokalnych mieszkańców w kawiarni w Prizrenie i chcesz porozmawiać naturalnie. Dziś uczysz się prostych pytań o życie, podróż i zainteresowania.`, vocab: [{sq: `bisedë`, pl: `rozmowa`, ipa: `/bi-se-də/`},{sq: `shoqëri`, pl: `towarzystwo`, ipa: `/szo-czə-ri/`},{sq: `punë`, pl: `praca`, ipa: `/pu-nə/`},{sq: `jetë`, pl: `życie`, ipa: `/je-tə/`},{sq: `hobi`, pl: `hobby`, ipa: `/ho-bi/`},{sq: `muzikë`, pl: `muzyka`, ipa: `/mu-zi-kə/`},{sq: `film`, pl: `film`, ipa: `/film/`},{sq: `libër`, pl: `książka`, ipa: `/li-bər/`},{sq: `udhëtim`, pl: `podróż`, ipa: `/udhə-tim/`},{sq: `qejf`, pl: `przyjemność, ochota`, ipa: `/czejf/`}], phrases: [{sq: `Çfarë pune bëni?`, pl: `Czym się pan/pani zajmuje?`, ipa: `/czfa-rə pu-ne bə-ni/`},{sq: `A ju pëlqen muzika?`, pl: `Czy lubi pan/pani muzykę?`, ipa: `/a ju pəl-czen mu-zi-ka/`},{sq: `Më pëlqen shumë këtu.`, pl: `Bardzo mi się tutaj podoba.`, ipa: `/mə pəl-czen szu-mə kə-tu/`},{sq: `Sa kohë qëndroni këtu?`, pl: `Jak długo pan/pani tu zostaje?`, ipa: `/sa ko-hə czən-dro-ni kə-tu/`},{sq: `Jam këtu për pushime.`, pl: `Jestem tu na wakacjach.`, ipa: `/jam kə-tu pər pu-shi-me/`},{sq: `Ishte kënaqësi.`, pl: `To była przyjemność.`, ipa: `/isz-te kə-na-czə-si/`}], grammar: `Më pëlqen oznacza „podoba mi się” lub „lubię”. Dla wielu rzeczy mówi się më pëlqejnë, ale na poziomie podróżnym możesz używać gotowych fraz. Për pushime oznacza „na wakacje”.`, practice: [`Powiedz, że bardzo ci się tutaj podoba.`,`Zapytaj kogoś, czym się zajmuje.`,`Powiedz, że jesteś tu na wakacjach.`,`Zapytaj, czy ktoś lubi muzykę.`,`Zakończ rozmowę zwrotem „to była przyjemność”.`]},{day: 25, title: `Jedzenie specjalne i alergie`, title_native: `Ushqim i veçantë dhe alergji`, focus: `W restauracji musisz powiedzieć o alergii albo diecie. Dziś uczysz się jasno komunikować, czego nie możesz jeść.`, vocab: [{sq: `alergji`, pl: `alergia`, ipa: `/a-ler-gji/`},{sq: `gluten`, pl: `gluten`, ipa: `/glu-ten/`},{sq: `qumësht`, pl: `mleko`, ipa: `/czu-məszt/`},{sq: `arra`, pl: `orzechy`, ipa: `/ar-ra/`},{sq: `mish`, pl: `mięso`, ipa: `/misz/`},{sq: `peshk`, pl: `ryba`, ipa: `/peszk/`},{sq: `vegjetarian`, pl: `wegetariański`, ipa: `/ve-gje-ta-rian/`},{sq: `pa`, pl: `bez`, ipa: `/pa/`},{sq: `me`, pl: `z`, ipa: `/me/`},{sq: `kujdes`, pl: `uwaga, ostrożność`, ipa: `/kuj-des/`}], phrases: [{sq: `Kam alergji ndaj arrave.`, pl: `Mam alergię na orzechy.`, ipa: `/kam a-ler-gji ndaj ar-ra-ve/`},{sq: `Nuk mund të ha gluten.`, pl: `Nie mogę jeść glutenu.`, ipa: `/nuk mund tə ha glu-ten/`},{sq: `A ka qumësht këtu?`, pl: `Czy jest tu mleko?`, ipa: `/a ka czu-məszt kə-tu/`},{sq: `Dua diçka vegjetariane.`, pl: `Chcę coś wegetariańskiego.`, ipa: `/du-a di-czka ve-gje-ta-ria-ne/`},{sq: `Pa mish, ju lutem.`, pl: `Bez mięsa, proszę.`, ipa: `/pa misz ju lu-tem/`},{sq: `Ju lutem, kini kujdes.`, pl: `Proszę zachować ostrożność.`, ipa: `/ju lu-tem ki-ni kuj-des/`}], grammar: `Nuk mund të oznacza „nie mogę” i jest mocniejsze niż samo „nie jem”. Ndaj używa się w zwrotach typu alergia na coś. Przy alergiach lepiej mówić pełnym zdaniem i dodać ju lutem, kini kujdes.`, practice: [`Powiedz, że masz alergię na orzechy.`,`Powiedz, że nie możesz jeść glutenu.`,`Zapytaj, czy danie zawiera mleko.`,`Poproś o coś wegetariańskiego.`,`Poproś obsługę o ostrożność.`]},{day: 26, title: `Bank, pieniądze i wymiana`, title_native: `Banka, paratë dhe këmbimi`, focus: `Potrzebujesz gotówki lub wymiany pieniędzy w Tiranie. Nauczysz się pytać o bankomat, prowizję, kurs i płatność.`, vocab: [{sq: `bankë`, pl: `bank`, ipa: `/ban-kə/`},{sq: `bankomat`, pl: `bankomat`, ipa: `/ban-ko-mat/`},{sq: `para`, pl: `pieniądze`, ipa: `/pa-ra/`},{sq: `euro`, pl: `euro`, ipa: `/eu-ro/`},{sq: `lekë`, pl: `leki albańskie`, ipa: `/le-kə/`},{sq: `këmbim`, pl: `wymiana`, ipa: `/kəm-bim/`},{sq: `kurs`, pl: `kurs`, ipa: `/kurs/`},{sq: `komision`, pl: `prowizja`, ipa: `/ko-mi-sion/`},{sq: `faturë`, pl: `rachunek, faktura`, ipa: `/fa-tu-rə/`},{sq: `pagesë`, pl: `płatność`, ipa: `/pa-ge-sə/`}], phrases: [{sq: `Ku ka bankomat?`, pl: `Gdzie jest bankomat?`, ipa: `/ku ka ban-ko-mat/`},{sq: `Dua të ndërroj euro.`, pl: `Chcę wymienić euro.`, ipa: `/du-a tə ndər-roj eu-ro/`},{sq: `Cili është kursi?`, pl: `Jaki jest kurs?`, ipa: `/ci-li əszt kur-si/`},{sq: `A ka komision?`, pl: `Czy jest prowizja?`, ipa: `/a ka ko-mi-sion/`},{sq: `Mund të paguaj me kartë?`, pl: `Czy mogę zapłacić kartą?`, ipa: `/mund tə pa-gu-aj me kar-tə/`},{sq: `Kam nevojë për faturë.`, pl: `Potrzebuję rachunku.`, ipa: `/kam ne-vo-jə pər fa-tu-rə/`}], grammar: `Dua të ndërroj oznacza „chcę wymienić”. Cili është...? znaczy „jaki jest...?” dla rzeczowników rodzaju męskiego. W punktach wymiany warto zawsze zapytać o kurs i prowizję, używając krótkich pytań.`, practice: [`Zapytaj, gdzie jest bankomat.`,`Powiedz, że chcesz wymienić euro.`,`Zapytaj o kurs.`,`Zapytaj, czy jest prowizja.`,`Poproś o rachunek.`]},{day: 27, title: `Umawianie spotkań`, title_native: `Takimet`, focus: `Chcesz spotkać się z nowo poznaną osobą na kawę w Tiranie. Dziś ćwiczysz proponowanie godziny, miejsca i potwierdzanie planu.`, vocab: [{sq: `takim`, pl: `spotkanie`, ipa: `/ta-kim/`},{sq: `kafe`, pl: `kawa, kawiarnia`, ipa: `/ka-fe/`},{sq: `sonte`, pl: `dziś wieczorem`, ipa: `/son-te/`},{sq: `nesër`, pl: `jutro`, ipa: `/ne-sər/`},{sq: `pasdite`, pl: `popołudnie`, ipa: `/pas-di-te/`},{sq: `vend`, pl: `miejsce`, ipa: `/vend/`},{sq: `kohë`, pl: `czas`, ipa: `/ko-hə/`},{sq: `dakord`, pl: `zgoda, okej`, ipa: `/da-kord/`},{sq: `vonë`, pl: `późno`, ipa: `/vo-nə/`},{sq: `herët`, pl: `wcześnie`, ipa: `/he-rət/`}], phrases: [{sq: `A ke kohë sot?`, pl: `Czy masz dziś czas?`, ipa: `/a ke ko-hə sot/`},{sq: `Takohemi për kafe?`, pl: `Spotkamy się na kawę?`, ipa: `/ta-ko-he-mi pər ka-fe/`},{sq: `Në cilën orë?`, pl: `O której godzinie?`, ipa: `/nə ci-lən o-rə/`},{sq: `A është mirë në gjashtë?`, pl: `Czy o szóstej jest dobrze?`, ipa: `/a əszt mir nə gjasht/`},{sq: `Le të takohemi këtu.`, pl: `Spotkajmy się tutaj.`, ipa: `/le tə ta-ko-he-mi kə-tu/`},{sq: `Dakord, shihemi nesër.`, pl: `Zgoda, widzimy się jutro.`, ipa: `/da-kord szi-he-mi ne-sər/`}], grammar: `A ke...? to nieformalna forma „czy masz...?”, używana z osobami, z którymi jesteś na ty. Forma grzeczna to a keni. Le të... oznacza „zróbmy...”, np. le të takohemi — spotkajmy się.`, practice: [`Zapytaj nieformalnie, czy ktoś ma dziś czas.`,`Zaproponuj kawę.`,`Zaproponuj godzinę szóstą.`,`Ustal miejsce spotkania.`,`Potwierdź plan na jutro.`]},{day: 28, title: `Opinie i preferencje`, title_native: `Mendimet dhe preferencat`, focus: `Rozmawiasz o jedzeniu, mieście i podróży. Dziś uczysz się mówić, co lubisz, czego nie lubisz i co uważasz za piękne, drogie lub ciekawe.`, vocab: [{sq: `mendim`, pl: `opinia`, ipa: `/men-dim/`},{sq: `më pëlqen`, pl: `podoba mi się`, ipa: `/mə pəl-czen/`},{sq: `nuk më pëlqen`, pl: `nie podoba mi się`, ipa: `/nuk mə pəl-czen/`},{sq: `i bukur`, pl: `piękny`, ipa: `/i bu-kur/`},{sq: `interesant`, pl: `ciekawy`, ipa: `/in-te-re-sant/`},{sq: `i shtrenjtë`, pl: `drogi`, ipa: `/i sztrenjt/`},{sq: `i lirë`, pl: `tani`, ipa: `/i li-rə/`},{sq: `i mirë`, pl: `dobry`, ipa: `/i mir/`},{sq: `i keq`, pl: `zły`, ipa: `/i kecz/`},{sq: `më shumë`, pl: `bardziej, więcej`, ipa: `/mə szu-mə/`}], phrases: [{sq: `Më pëlqen ky qytet.`, pl: `Podoba mi się to miasto.`, ipa: `/mə pəl-czen ky czy-tet/`},{sq: `Nuk më pëlqen kjo pjatë.`, pl: `Nie podoba mi się to danie.`, ipa: `/nuk mə pəl-czen kjo pja-tə/`},{sq: `Është shumë interesant.`, pl: `To jest bardzo ciekawe.`, ipa: `/əszt szu-mə in-te-re-sant/`},{sq: `Më pëlqen më shumë deti.`, pl: `Bardziej podoba mi się morze.`, ipa: `/mə pəl-czen mə szu-mə de-ti/`},{sq: `Ky vend është i bukur.`, pl: `To miejsce jest piękne.`, ipa: `/ky vend əszt i bu-kur/`},{sq: `Çfarë mendoni?`, pl: `Co pan/pani myśli?`, ipa: `/czfa-rə men-do-ni/`}], grammar: `Ky to „ten” dla rodzaju męskiego, kjo to „ta/to” dla żeńskiego lub rzeczy bliskiej. Më shumë może znaczyć „bardziej” albo „więcej”. Przy opiniach używaj prostych schematów: më pëlqen, nuk më pëlqen, është shumë...`, practice: [`Powiedz, że podoba ci się miasto.`,`Powiedz, że nie podoba ci się danie.`,`Opisz miejsce jako piękne.`,`Zapytaj kogoś o opinię.`,`Porównaj: bardziej lubisz morze czy góry.`]},{day: 29, title: `Plany, przeszłość i podróż`, title_native: `Planet, e kaluara dhe udhëtimi`, focus: `Pod koniec pobytu opowiadasz, gdzie byłeś i dokąd jedziesz dalej. Dziś łączysz przeszłość, teraźniejszość i przyszłość w prostych zdaniach.`, vocab: [{sq: `isha`, pl: `byłem/byłam`, ipa: `/i-sza/`},{sq: `jam`, pl: `jestem`, ipa: `/jam/`},{sq: `do të jem`, pl: `będę`, ipa: `/do tə jem/`},{sq: `shkova`, pl: `poszedłem/pojechałem`, ipa: `/szko-va/`},{sq: `do të shkoj`, pl: `pójdę/pojadę`, ipa: `/do tə szkoj/`},{sq: `pashë`, pl: `zobaczyłem`, ipa: `/pa-szə/`},{sq: `vizitova`, pl: `odwiedziłem`, ipa: `/vi-zi-to-va/`},{sq: `qëndrova`, pl: `zostałem`, ipa: `/czən-dro-va/`},{sq: `udhëtova`, pl: `podróżowałem`, ipa: `/udhə-to-va/`},{sq: `pushime`, pl: `wakacje`, ipa: `/pu-shi-me/`}], phrases: [{sq: `Isha në Tiranë.`, pl: `Byłem w Tiranie.`, ipa: `/i-sza nə ti-ra-nə/`},{sq: `Vizitova muzeun.`, pl: `Odwiedziłem muzeum.`, ipa: `/vi-zi-to-va mu-ze-un/`},{sq: `Pashë detin.`, pl: `Zobaczyłem morze.`, ipa: `/pa-szə de-tin/`},{sq: `Nesër do të shkoj në Berat.`, pl: `Jutro pojadę do Beratu.`, ipa: `/ne-sər do tə szkoj nə be-rat/`},{sq: `Do të qëndroj dy ditë.`, pl: `Zostanę dwa dni.`, ipa: `/do tə czən-droj dy di-tə/`},{sq: `Udhëtimi ishte shumë i mirë.`, pl: `Podróż była bardzo dobra.`, ipa: `/udhə-ti-mi isz-te szu-mə i mir/`}], grammar: `Do të tworzy przyszłość, a wiele form przeszłych ma charakterystyczne końcówki, np. vizitova, qëndrova. Nie musisz znać całej tabeli odmiany, aby opowiedzieć o podróży. Ucz się gotowych zdań: byłem, odwiedziłem, jutro pojadę.`, practice: [`Powiedz, że byłeś w Tiranie.`,`Powiedz, że odwiedziłeś muzeum.`,`Powiedz, że jutro jedziesz do Beratu.`,`Powiedz, że zostaniesz dwa dni.`,`Opisz swoją podróż jednym zdaniem w czasie przeszłym.`]},{day: 30, title: `Powtórka podróżna i pewność w rozmowie`, title_native: `Përsëritje për udhëtim`, focus: `Ostatniego dnia łączysz wszystko: hotel, jedzenie, transport, pomoc i small talk. Celem jest mówić prosto, ale samodzielnie w realnych sytuacjach w Albanii lub Kosowie.`, vocab: [{sq: `përsëri`, pl: `znowu, ponownie`, ipa: `/pər-sə-ri/`},{sq: `ngadalë`, pl: `wolno`, ipa: `/nga-da-lə/`},{sq: `kuptoj`, pl: `rozumiem`, ipa: `/kup-toj/`},{sq: `nuk kuptoj`, pl: `nie rozumiem`, ipa: `/nuk kup-toj/`},{sq: `flisni`, pl: `mówicie, proszę mówić`, ipa: `/flis-ni/`},{sq: `shqip`, pl: `po albańsku`, ipa: `/szczip/`},{sq: `anglisht`, pl: `po angielsku`, ipa: `/an-glisht/`},{sq: `polonisht`, pl: `po polsku`, ipa: `/po-lo-nisht/`},{sq: `gati`, pl: `gotowy`, ipa: `/ga-ti/`},{sq: `sigurisht`, pl: `oczywiście`, ipa: `/si-gu-risht/`}], phrases: [{sq: `Nuk kuptoj.`, pl: `Nie rozumiem.`, ipa: `/nuk kup-toj/`},{sq: `Flisni më ngadalë, ju lutem.`, pl: `Proszę mówić wolniej.`, ipa: `/flis-ni mə nga-da-lə ju lu-tem/`},{sq: `A flisni anglisht?`, pl: `Czy mówi pan/pani po angielsku?`, ipa: `/a flis-ni an-glisht/`},{sq: `Unë flas pak shqip.`, pl: `Mówię trochę po albańsku.`, ipa: `/u-nə flas pak szczip/`},{sq: `Mund ta përsërisni?`, pl: `Czy może pan/pani powtórzyć?`, ipa: `/mund ta pər-sə-ris-ni/`},{sq: `Jam gati.`, pl: `Jestem gotowy/gotowa.`, ipa: `/jam ga-ti/`}], grammar: `Flas oznacza „mówię”, a flisni może znaczyć „mówicie” albo uprzejme „proszę mówić”. Pak oznacza „trochę”, więc unë flas pak shqip to idealne zdanie dla podróżnika. Gdy nie rozumiesz, użyj nuk kuptoj i poproś o wolniejsze powtórzenie.`, practice: [`Powiedz, że mówisz trochę po albańsku.`,`Poproś rozmówcę, żeby mówił wolniej.`,`Zapytaj, czy ktoś mówi po angielsku.`,`Poproś o powtórzenie zdania.`,`Odegraj jedną pełną scenkę: hotel, kawiarnia albo taksówka.`]}];

var CONVERSATIONS_PL_SQ = [{id: 1, title: `Zamawianie kawy w Tiranie`, scene: `Jesteś w małej kawiarni w dzielnicy Blloku w Tiranie. Barista wita cię i pyta o zamówienie. Chcesz kawę bez cukru i wodę.`, lines: [{who: `them`, sq: `Mirëdita, çfarë dëshironi?`, pl: `Dzień dobry, czego pan/pani sobie życzy?`},{who: `you`, sq: `Mirëdita, një kafe, ju lutem.`, pl: `Dzień dobry, jedną kawę, proszę.`},{who: `them`, sq: `Me sheqer apo pa sheqer?`, pl: `Z cukrem czy bez cukru?`},{who: `you`, sq: `Pa sheqer, ju lutem.`, pl: `Bez cukru, proszę.`},{who: `them`, sq: `Dëshironi edhe ujë?`, pl: `Czy chce pan/pani też wodę?`},{who: `you`, sq: `Po, një ujë të ftohtë.`, pl: `Tak, jedną zimną wodę.`},{who: `them`, sq: `Këtu apo për ta marrë?`, pl: `Tutaj czy na wynos?`},{who: `you`, sq: `Këtu, ju lutem.`, pl: `Tutaj, proszę.`},{who: `them`, sq: `Urdhëroni, kafeja juaj.`, pl: `Proszę, pana/pani kawa.`},{who: `you`, sq: `Faleminderit, sa kushton?`, pl: `Dziękuję, ile kosztuje?`},{who: `them`, sq: `Dy euro.`, pl: `Dwa euro.`},{who: `you`, sq: `Ja ku janë, faleminderit.`, pl: `Proszę, oto one, dziękuję.`}]},{id: 2, title: `Meldowanie w hotelu w Durrës`, scene: `Przyjeżdżasz do hotelu blisko plaży w Durrës. Masz rezerwację na dwie noce i podajesz paszport. Pytasz też o śniadanie.`, lines: [{who: `them`, sq: `Mirëmbrëma, mirë se vini.`, pl: `Dobry wieczór, witamy.`},{who: `you`, sq: `Mirëmbrëma, kam një rezervim.`, pl: `Dobry wieczór, mam rezerwację.`},{who: `them`, sq: `Në cilin emër është rezervimi?`, pl: `Na jakie nazwisko jest rezerwacja?`},{who: `you`, sq: `Rezervimi është në emrin Cannon.`, pl: `Rezerwacja jest na nazwisko Cannon.`},{who: `them`, sq: `A mund të më jepni pasaportën?`, pl: `Czy może mi pan/pani dać paszport?`},{who: `you`, sq: `Po, ja pasaporta ime.`, pl: `Tak, oto mój paszport.`},{who: `them`, sq: `Dhoma juaj është në katin e dytë.`, pl: `Pana/pani pokój jest na drugim piętrze.`},{who: `you`, sq: `Faleminderit, a ka mëngjes?`, pl: `Dziękuję, czy jest śniadanie?`},{who: `them`, sq: `Po, mëngjesi është nga ora shtatë deri në dhjetë.`, pl: `Tak, śniadanie jest od siódmej do dziesiątej.`},{who: `you`, sq: `Shumë mirë, ku është ashensori?`, pl: `Bardzo dobrze, gdzie jest winda?`},{who: `them`, sq: `Ashensori është majtas.`, pl: `Winda jest po lewej.`},{who: `you`, sq: `Faleminderit shumë.`, pl: `Bardzo dziękuję.`}]},{id: 3, title: `Pytanie o drogę w Berat`, scene: `Spacerujesz po Berat i szukasz drogi do zamku. Zaczepiasz lokalną osobę na placu. Chcesz wiedzieć, czy droga jest daleko.`, lines: [{who: `you`, sq: `Më falni, ku është kështjella?`, pl: `Przepraszam, gdzie jest zamek?`},{who: `them`, sq: `Kështjella është atje lart.`, pl: `Zamek jest tam na górze.`},{who: `you`, sq: `A është larg?`, pl: `Czy to daleko?`},{who: `them`, sq: `Jo shumë, rreth njëzet minuta.`, pl: `Nie bardzo, około dwadzieścia minut.`},{who: `you`, sq: `Si mund të shkoj atje?`, pl: `Jak mogę tam dojść?`},{who: `them`, sq: `Shkoni drejt dhe pastaj kthehuni majtas.`, pl: `Proszę iść prosto, a potem skręcić w lewo.`},{who: `you`, sq: `Pas kësaj?`, pl: `A potem?`},{who: `them`, sq: `Pastaj ndiqni rrugën deri në hyrje.`, pl: `Potem proszę iść drogą aż do wejścia.`},{who: `you`, sq: `A ka bileta atje?`, pl: `Czy są tam bilety?`},{who: `them`, sq: `Po, mund të blini bileta te hyrja.`, pl: `Tak, można kupić bilety przy wejściu.`},{who: `you`, sq: `Faleminderit për ndihmën.`, pl: `Dziękuję za pomoc.`},{who: `them`, sq: `Me kënaqësi.`, pl: `Z przyjemnością.`}]},{id: 4, title: `Kolacja w restauracji nad morzem`, scene: `Jesteś w restauracji w Sarandzie i chcesz zamówić danie bez mięsa. Pytasz kelnera o rekomendację i prosisz o rachunek po posiłku.`, lines: [{who: `them`, sq: `Mirëmbrëma, a keni rezervim?`, pl: `Dobry wieczór, czy ma pan/pani rezerwację?`},{who: `you`, sq: `Jo, a ka tavolinë të lirë?`, pl: `Nie, czy jest wolny stolik?`},{who: `them`, sq: `Po, urdhëroni këtu.`, pl: `Tak, proszę tutaj.`},{who: `you`, sq: `A keni menu?`, pl: `Czy macie menu?`},{who: `them`, sq: `Po, ja menuja.`, pl: `Tak, oto menu.`},{who: `you`, sq: `Çfarë rekomandoni pa mish?`, pl: `Co pan/pani poleca bez mięsa?`},{who: `them`, sq: `Rekomandoj sallatën dhe peshkun.`, pl: `Polecam sałatkę i rybę.`},{who: `you`, sq: `Dua sallatën, pa mish, ju lutem.`, pl: `Chcę sałatkę, bez mięsa, proszę.`},{who: `them`, sq: `Dëshironi ujë apo verë?`, pl: `Chce pan/pani wodę czy wino?`},{who: `you`, sq: `Një ujë të ftohtë, ju lutem.`, pl: `Jedną zimną wodę, proszę.`},{who: `them`, sq: `Si ishte ushqimi?`, pl: `Jakie było jedzenie?`},{who: `you`, sq: `Ishte shumë e shijshme, faturën ju lutem.`, pl: `Było bardzo smaczne, rachunek proszę.`}]},{id: 5, title: `Kupowanie biletu autobusowego`, scene: `Jesteś na przystanku autobusowym w Tiranie i chcesz pojechać do centrum. Pytasz o bilet, kierunek i czas podróży. Rozmowa jest krótka i praktyczna.`, lines: [{who: `them`, sq: `Mirëdita, ku doni të shkoni?`, pl: `Dzień dobry, dokąd chce pan/pani jechać?`},{who: `you`, sq: `Dua të shkoj në qendër.`, pl: `Chcę jechać do centrum.`},{who: `them`, sq: `Ky autobus shkon në qendër.`, pl: `Ten autobus jedzie do centrum.`},{who: `you`, sq: `Sa kushton bileta?`, pl: `Ile kosztuje bilet?`},{who: `them`, sq: `Pesëdhjetë lekë.`, pl: `Pięćdziesiąt leków.`},{who: `you`, sq: `Dua një biletë, ju lutem.`, pl: `Chcę jeden bilet, proszę.`},{who: `them`, sq: `Urdhëroni bileta.`, pl: `Proszę, bilet.`},{who: `you`, sq: `Sa zgjat udhëtimi?`, pl: `Ile trwa podróż?`},{who: `them`, sq: `Rreth pesëmbëdhjetë minuta.`, pl: `Około piętnaście minut.`},{who: `you`, sq: `A mund të zbres te sheshi?`, pl: `Czy mogę wysiąść przy placu?`},{who: `them`, sq: `Po, zbrisni te ndalesa tjetër.`, pl: `Tak, proszę wysiąść na następnym przystanku.`},{who: `you`, sq: `Faleminderit.`, pl: `Dziękuję.`}]},{id: 6, title: `Zakupy na targu w Krujë`, scene: `Na targu w Krujë oglądasz ręcznie robioną pamiątkę. Chcesz zapytać o cenę, poprosić o coś tańszego i zapłacić gotówką. Sprzedawca mówi uprzejmie i prosto.`, lines: [{who: `them`, sq: `Mirëdita, a mund t’ju ndihmoj?`, pl: `Dzień dobry, czy mogę pomóc?`},{who: `you`, sq: `Po, sa kushton kjo?`, pl: `Tak, ile to kosztuje?`},{who: `them`, sq: `Kushton një mijë lekë.`, pl: `Kosztuje tysiąc leków.`},{who: `you`, sq: `Është pak shtrenjtë.`, pl: `To trochę drogo.`},{who: `them`, sq: `Kam edhe diçka më të lirë.`, pl: `Mam też coś tańszego.`},{who: `you`, sq: `A mund ta shoh?`, pl: `Czy mogę to zobaczyć?`},{who: `them`, sq: `Po, urdhëroni.`, pl: `Tak, proszę.`},{who: `you`, sq: `Kjo më pëlqen.`, pl: `To mi się podoba.`},{who: `them`, sq: `Kjo kushton shtatëqind lekë.`, pl: `To kosztuje siedemset leków.`},{who: `you`, sq: `Dua ta blej.`, pl: `Chcę to kupić.`},{who: `them`, sq: `Me kartë apo me para?`, pl: `Kartą czy gotówką?`},{who: `you`, sq: `Me para, faleminderit.`, pl: `Gotówką, dziękuję.`}]},{id: 7, title: `W aptece z bólem głowy`, scene: `W Tiranie boli cię głowa i wchodzisz do apteki. Chcesz poprosić o lekarstwo i upewnić się, że wiesz, jak je przyjmować. Mówisz krótko i jasno.`, lines: [{who: `them`, sq: `Mirëdita, si mund t’ju ndihmoj?`, pl: `Dzień dobry, jak mogę pomóc?`},{who: `you`, sq: `Kam dhimbje koke.`, pl: `Boli mnie głowa.`},{who: `them`, sq: `A keni temperaturë?`, pl: `Czy ma pan/pani temperaturę?`},{who: `you`, sq: `Jo, nuk kam temperaturë.`, pl: `Nie, nie mam temperatury.`},{who: `them`, sq: `A keni alergji?`, pl: `Czy ma pan/pani alergię?`},{who: `you`, sq: `Po, kam alergji ndaj arrave.`, pl: `Tak, mam alergię na orzechy.`},{who: `them`, sq: `Ky ilaç është për dhimbje koke.`, pl: `To lekarstwo jest na ból głowy.`},{who: `you`, sq: `Si duhet ta marr?`, pl: `Jak mam je przyjmować?`},{who: `them`, sq: `Merreni me ujë, pas ushqimit.`, pl: `Proszę wziąć z wodą, po jedzeniu.`},{who: `you`, sq: `Sa kushton?`, pl: `Ile kosztuje?`},{who: `them`, sq: `Tre euro.`, pl: `Trzy euro.`},{who: `you`, sq: `Faleminderit për ndihmën.`, pl: `Dziękuję za pomoc.`}]},{id: 8, title: `Small talk z lokalną osobą w Prizrenie`, scene: `Siedzisz w kawiarni w Prizrenie i rozmawiasz z lokalną osobą przy sąsiednim stoliku. Chcesz powiedzieć, że jesteś z Polski, że miasto ci się podoba i zapytać o rekomendacje. Rozmowa jest przyjazna i nieformalna.`, lines: [{who: `you`, sq: `Përshëndetje, a flisni anglisht?`, pl: `Cześć, czy mówi pan/pani po angielsku?`},{who: `them`, sq: `Po, pak, po edhe shqip.`, pl: `Tak, trochę, ale też po albańsku.`},{who: `you`, sq: `Unë flas pak shqip.`, pl: `Mówię trochę po albańsku.`},{who: `them`, sq: `Shumë mirë, nga jeni?`, pl: `Bardzo dobrze, skąd pan/pani jest?`},{who: `you`, sq: `Jam nga Polonia.`, pl: `Jestem z Polski.`},{who: `them`, sq: `A ju pëlqen Prizreni?`, pl: `Czy podoba się panu/pani Prizren?`},{who: `you`, sq: `Po, më pëlqen shumë ky qytet.`, pl: `Tak, bardzo podoba mi się to miasto.`},{who: `them`, sq: `Sa kohë qëndroni këtu?`, pl: `Jak długo pan/pani tu zostaje?`},{who: `you`, sq: `Qëndroj dy ditë.`, pl: `Zostaję dwa dni.`},{who: `them`, sq: `Duhet të vizitoni kalanë.`, pl: `Powinien/powinna pan/pani odwiedzić twierdzę.`},{who: `you`, sq: `Faleminderit, do të shkoj nesër.`, pl: `Dziękuję, pójdę jutro.`},{who: `them`, sq: `Ju uroj udhëtim të bukur.`, pl: `Życzę pięknej podróży.`}]}];